// client/src/hooks/useTelegram.js
import { useEffect, useState } from 'react';

export function useTelegram() {
  const [tg, setTg] = useState(() => {
    if (window.Telegram?.WebApp) {
      return window.Telegram.WebApp;
    }
    return null;
  });

  const [user, setUser] = useState(null);

  useEffect(() => {
    if (tg) {
      // Получаем данные пользователя из Telegram WebApp
      try {
        const userData = tg.initDataUnsafe?.user;
        if (userData) {
          setUser(userData);
        }
      } catch (error) {
        console.error('Ошибка при получении данных пользователя Telegram:', error);
      }

      // Настраиваем внешний вид Telegram WebApp
      tg.expand();
      tg.enableClosingConfirmation();

      // Устанавливаем тему
      const colorScheme = tg.colorScheme || 'light';
      document.documentElement.dataset.theme = colorScheme;

      // Кнопка назад
      tg.BackButton.isVisible = false;
    }
  }, [tg]);

  // Функция для показа/скрытия кнопки назад
  const showBackButton = (show = true) => {
    if (tg && tg.BackButton) {
      tg.BackButton.isVisible = show;
    }
  };

  // Функция для установки действия при нажатии на кнопку назад
  const onBackButtonClick = (callback) => {
    if (tg && tg.BackButton) {
      tg.BackButton.onClick(callback);
    }
  };

  // Функция для закрытия Telegram WebApp
  const closeApp = () => {
    if (tg) {
      tg.close();
    }
  };

  return {
    tg,
    user,
    showBackButton,
    onBackButtonClick,
    closeApp
  };
}
